#include <stdio.h>

int main() {
    int n = 1234;
    int reverse = 0;
    int temp;

    printf("Original number: %d\n", n);

    while(n != 0) {
        temp = n % 10;
        reverse = reverse * 10 + temp;
        n = n / 10;
    }

    printf("Reversed number: %d\n", reverse);
    return 0;
}

#include <stdio.h>

void reverseNum(int *n) {
    int rev = 0;
    int val = *n;
    while(val != 0) {
        rev = rev * 10 + (val % 10);
        val = val / 10;
    }
    *n = rev;
}

int main() {
    int num = 5678;
    printf("Before reverse: %d\n", num);

    reverseNum(&num);

    printf("After reverse: %d\n", num);
    return 0;
}

#include <stdio.h>

void swap(int x, int y) {
    int temp;
    printf("Inside swap function (before): x=%d, y=%d\n", x, y);
    temp = x;
    x = y;
    y = temp;
    printf("Inside swap function (after): x=%d, y=%d\n", x, y);
}

int main() {
    int a = 10;
    int b = 20;
    printf("Before swap: a=%d, b=%d\n", a, b);

    swap(a, b);

    printf("After swap in main: a=%d, b=%d (Values did not change!)\n", a, b);
    return 0;
}

#include <stdio.h>

void swap(int *x, int *y) {
    int temp;
    printf("Swapping values at addresses %p and %p\n", x, y);
    temp = *x;
    *x = *y;
    *y = temp;
}

int main() {
    int a = 10;
    int b = 20;
    printf("Before swap: a=%d, b=%d\n", a, b);

    swap(&a, &b);

    printf("After swap: a=%d, b=%d (Successfully swapped!)\n", a, b);
    return 0;
}
